    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xEFE9E5F5FEBE0A25ULL + 0xD9EEC8BDC84DC5EEULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xE44A109814502791ULL + 0x879BF23130C9B99AULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseA(pNonce * 0xB8B9EB506B97AC2BULL + 0x8D9F1179B9FB9615ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xAFEFCE14BBE2A7E7ULL + 0x8C7359940F0EA184ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xEBA7C85A378E25F1ULL + 0xCD42FFF268748956ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseC(pNonce * 0xC878CDC07994B0F5ULL + 0xF075AE34352E431BULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0x9161F0C95132279FULL + 0xC4410FF269B2D1F4ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xCC844E0A5B7728A7ULL + 0xB5BFD116AB1FC9DFULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xDDCA1F13F041C5BBULL + 0xE9BE4BD4165C56AAULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseA(pNonce * 0xF0196BF1FEC3084BULL + 0xCE4405AC1AB8EC80ULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseA(pNonce * 0x8CDA9F2F3C83686BULL + 0xD5C591DF8E800865ULL);
    std::uint64_t aDomainWordIngress = pConstants->mIngress;
