            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 3935U)) & S_BLOCK1], 37U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 4611U)) & S_BLOCK1], 26U);
