            aScatter = (RotL64(aIngress, 35U) + RotL64(aCross, 48U)) + (RotL64(aCarry, 3U) ^ RotL64(aPrevious, 23U));
            aScatter = TwistMix64::DiffuseB(((aScatter ^ aDomainWordScatter) ^ aNonceWordK));
