            aOrbiterA = ((aWandererA + RotL64(aCross, 57U)) + RotL64(aCarry, 5U)) + 1001439027670862297U;
            aOrbiterH = (aWandererF + RotL64(aScatter, 21U)) + 4668935191943035233U;
            aOrbiterF = ((aWandererC + RotL64(aIngress, 12U)) + RotL64(aCarry, 41U)) + 10850768315784837204U;
            aOrbiterC = (((aWandererG + RotL64(aPrevious, 5U)) + 5919934531368226691U) + aOrbiterAssignSaltF[(((31U - aIndex) + 16U)) & S_SALT1]) + aNonceWordO;
            aOrbiterJ = ((aWandererI + RotL64(aScatter, 37U)) + 9965912824225172403U) + aOrbiterAssignSaltD[(((31U - aIndex) + 3U)) & S_SALT1];
            aOrbiterK = ((aWandererK + RotL64(aCross, 39U)) + 2998668499421972033U) + aNonceWordG;
