            //
            aOrbiterB = ((aOrbiterB + aOrbiterI) + 16373155026891811434U) + aOrbiterUpdateSaltB[((aIndex + 14U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterB) ^ 8637408676940734518U;
            aOrbiterE = RotL64((aOrbiterE * 8926439529160364473U), 3U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterK) + 13944685351547296660U) + aNonceWordG;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterI) ^ 520641527075228150U;
            aOrbiterJ = RotL64((aOrbiterJ * 15055637437350596167U), 23U);
